class Solution:
    def minCostToMoveChips(self, position):
        best = None
        for target in position:
            cost = 0
            for p in position:
                if (p - target) % 2 != 0:
                    cost += 1
            if best is None or cost < best:
                best = cost
        return best

solutions.python:
class Solution:
    def minCostToMoveChips(self, position):
        odd = sum(1 for p in position if p % 2)
        return min(odd, len(position) - odd)

